@Override
public void updateState(IDispatcher<Graphics> disp) {
	// Scale diameter based on x position relative to container width
	// Creates perspective effect: larger on right (toward viewer), smaller on left (away from viewer)
	int width = dimension.getWidth();
	float ratio = (float) position.x / width;
	diameter = (int) (10 + ratio * 30); // Scale diameter between 10 and 40 pixels
}

