/**
 * Generates an ABall
 * @param ballType - the type of ABall to be generated. Input from the view
 */
public void makeBall(String ballType) {
	// Create a ball instance using the loader with random constructor arguments
	Object[] args = new Object[] {
		Randomizer.Singleton.randomColor(),
		Randomizer.Singleton.randomPos(new Rectangle(model2ViewAdpt.getDimension().getWidth(), model2ViewAdpt.getDimension().getHeight())),
		Randomizer.Singleton.randomVel(new Rectangle(20, 20)),
		Randomizer.Singleton.randomDiameter(),
		model2ViewAdpt.getDimension()
	};
	IObserver<Graphics> ball = loader.load(ballType, args);
	ballDispatcher.addObserver(ball);
}

