    89→	public void loadBall(IUpdateStrategy strategy) {
    90→		//TODO: Move all the GUI-related code to the view
    91→		IRandomizer rand = Randomizer.Singleton;
    92→		int radius = rand.randomInt(5, 30);
    93→		Color color = rand.randomColor();
    94→		int xLoc = rand.randomInt(0, _controlAdpt.getCanvasDim().getWidth()); // subtract 30 so doesn't get stuck
    95→		int yLoc = rand.randomInt(0, _controlAdpt.getCanvasDim().getHeight());
    96→		int xVelocity = rand.randomInt(-10, 10);
    97→		int yVelocity = rand.randomInt(-10, 10);
    98→		
    99→		Ball newBall = new Ball(new Point(xLoc, yLoc), new Point(xVelocity, yVelocity), color, radius, _controlAdpt.getCanvasDim(), strategy);
   100→		myDispatcher.addObserver(newBall);
   101→	}
   102→
   103→	
   104→	/**
   105→	 * Returns an IStrategyFac that can instantiate the strategy specified by
   106→	 * class name. Returns a factory for a beeping error strategy if class name is null. 
   107→	 * The toString() of the returned factory is the class name.
   108→	 * 
   109→	 * @param classname  Shortened name of desired strategy
   110→	 * @return A factory to make that strategy
   111→	 */
   112→	public IStrategyFac makeStrategyFac(final String classname) {
   113→	    if (null == classname) return IStrategyFac.errorStrategyFac;
   114→	    return new IStrategyFac() {
   115→	        /**
   116→	         * Instantiate a strategy corresponding to the given class name.
   117→	         * @return An IUpdateStrategy instance
   118→	         */
   119→	        public IUpdateStrategy make() {
   120→	            return makeStrategy("hw03.model.strategy." + classname + "Strategy");
   121→	        }
   122→
   123→	        /**
   124→	         * Return the given class name string
   125→	         */
   126→	        public String toString() {
   127→	            return classname;
   128→	        }
   129→	    };
   130→	}
   131→	
   132→	/**
