   134→	 * @param strategy input ball class name
   135→	 * @return a strategy object
   136→	 */
   137→	public IUpdateStrategy makeStrategy(String strategy) {		
   138→		
   139→		IObjectLoader<IUpdateStrategy> loader = new ObjectLoader<IUpdateStrategy>(arg -> IUpdateStrategy.errorStrategy);
   140→		IUpdateStrategy newStrategy = loader.loadInstance(strategy);
   141→		return newStrategy;
   142→		
   143→	}
   144→	
   145→	/**
   146→	 * Returns an IStrategyFac that can instantiate a MultiStrategy with the two
   147→	 * strategies made by the two given IStrategyFac objects. Returns null if
   148→	 * either supplied factory is null. The toString() of the returned factory
   149→	 * is the toString()'s of the two given factories, concatenated with "-". 
   150→	 * If either factory is null, then a factory for a beeping error strategy is returned.
   151→	 * 
   152→	 * @param stratFac1 An IStrategyFac for a strategy
   153→	 * @param stratFac2 An IStrategyFac for a strategy
   154→	 * @return An IStrategyFac for the composition of the two strategies
   155→	 */
   156→	public IStrategyFac combineStrategyFacs(final IStrategyFac stratFac1, final IStrategyFac stratFac2) {
   157→	    if (null == stratFac1 || null == stratFac2) return IStrategyFac.errorStrategyFac;
   158→	    return new IStrategyFac() {
   159→			@Override
   160→			public IUpdateStrategy make() {
   161→				
   162→				return new IUpdateStrategy() {
   163→				
   164→		    	IUpdateStrategy strategy1 = stratFac1.make();
   165→		    	IUpdateStrategy strategy2 = stratFac2.make();
   166→				// TODO Auto-generated method stub
   167→		    	
   168→		    	@Override
   169→				public void updateState(IDispatcher<Graphics> disp, Ball ball) {
   170→		    		strategy1.updateState(disp, ball);
   171→		    		strategy2.updateState(disp, ball);
   172→		    	}};
   173→		    	}
   174→			
   175→			public String toString() {
   176→				return stratFac1.toString() + "-" + stratFac2.toString();
   177→			}
   178→	    };}
   179→
   180→    /**
   181→     * This is the method that is called by the view's adapter to the model, i.e. is called by IView2ModelAdapter.paint().
   182→     * This method will update the balls painted locations by painting all the balls
   183→     * onto the given Graphics object.
   184→     * @param g The Graphics object from the view's paintComponent() call.
   185→     */
   186→    public void update(Graphics g) {
   187→        myDispatcher.updateAll(g);  // The Graphics object is being given to all the balls (Observers) - used to update painted positions of balls
   188→    }
