    39→			System.err.println("WARNING!! [ObjectLoader] Using deprecated error factory type that discards the attempted classname:  "+classname);
    40→			return errorFac.apply(args); 
    41→		});
    42→	}
    43→	
    44→	/**
    45→	 * Constructor for the class.   The given errorFac is used to generate instances when the loadInstance() method
    46→	 * is otherwise unable to do so because of a processing error.
    47→	 * @param errorFac A factory method that takes 2 params, the same as loadInstance(): 
    48→	 * The attempted classname and the array of input parameters.  
    49→	 * The errorfFac function returns an instance of ReturnT.  
    50→	 */
    51→	public ObjectLoader(BiFunction<String, Object[], ReturnT> errorFac) {
    52→		super();
    53→		this.errorFac = errorFac;
    54→	}
    55→	
    56→
    57→	/**
    58→	 * Prints the given Exception to stderr and then invokes the stored errorFac to generate an error object.
    59→	 */
    60→	@Override
    61→	protected ReturnT errorHandler(Exception ex, String className, Object... args) {
    62→	
    63→		logger.log(LogLevel.ERROR, "\nObjectLoader.loadInstance(" + className + ", "
    64→				+ (new ArrayList<Object>(Arrays.asList(args))) + "):\n   Exception = " + ex);
    65→		ex.printStackTrace();
    66→		return errorFac.apply(className, args); // Make the error object
    67→	}
